import React, { useEffect, useState } from 'react';
import api from '../api'; 
import AppointmentCard from './AppointmentCard'; // Siguroha nga walay { }

const AppointmentList = () => {
    const [appointments, setAppointments] = useState([]);

    useEffect(() => {
        api.get('appointments/')
            .then((res: any) => setAppointments(res.data)) // Gi-fix ang : any
            .catch((err: any) => console.error("Error:", err)); // Gi-fix ang : any
    }, []);

    return (
        <div className="space-y-4">
            {appointments.map((a: any) => (
                <AppointmentCard 
                    key={a.appointment_id} 
                    appointment={a}
                    patient={a.patient}
                    doctor={a.doctor}
                    onEdit={() => {}}
                    onDelete={() => {}}
                />
            ))}
        </div>
    );
};

export default AppointmentList;
